-- PROGREX full Supabase setup SQL
-- Generated by scripts/export-supabase-sql.ts
begin;

create extension if not exists "pgcrypto";

create table if not exists roles (
  id uuid primary key default gen_random_uuid(),
  name text not null unique,
  description text,
  is_system boolean not null default false,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists permissions (
  key text primary key,
  label text not null,
  created_at timestamptz not null default now()
);

create table if not exists role_permissions (
  role_id uuid not null references roles(id) on delete cascade,
  permission_key text not null references permissions(key) on delete cascade,
  can_read boolean not null default false,
  can_write boolean not null default false,
  can_delete boolean not null default false,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  primary key(role_id, permission_key)
);

create table if not exists admin_users (
  id uuid primary key default gen_random_uuid(),
  email text not null unique,
  full_name text not null,
  password_hash text not null,
  role_id uuid references roles(id) on delete set null,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists services (
  id uuid primary key default gen_random_uuid(),
  slug text not null unique,
  title text not null,
  short_desc text,
  icon text,
  color text,
  details jsonb not null default '{}'::jsonb,
  sort_order int not null default 0,
  is_published boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists projects (
  id uuid primary key default gen_random_uuid(),
  slug text not null unique,
  title text not null,
  system_type text,
  industry text,
  categories text[] not null default '{}',
  tags text[] not null default '{}',
  image text,
  short_desc text,
  details jsonb not null default '{}'::jsonb,
  is_featured boolean not null default false,
  feature_order int not null default 999,
  is_published boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists team_members (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  role text not null,
  bio text,
  avatar text,
  linkedin text,
  github text,
  portfolio text,
  sort_order int not null default 0,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists blogs (
  id uuid primary key default gen_random_uuid(),
  slug text not null unique,
  title text not null,
  category text,
  author_name text,
  author_role text,
  author_avatar text,
  published_at text,
  read_time text,
  image text,
  excerpt text,
  tags text[] not null default '{}',
  content text,
  related_posts text[] not null default '{}',
  meta_title text,
  meta_description text,
  keywords text[] not null default '{}',
  is_published boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists ready_made_systems (
  id uuid primary key default gen_random_uuid(),
  slug text not null unique,
  name text not null,
  category text,
  industry text,
  tagline text,
  short_desc text,
  image text,
  has_demo boolean not null default false,
  details jsonb not null default '{}'::jsonb,
  sort_order int not null default 0,
  is_published boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists testimonials (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  role text,
  avatar text,
  quote text,
  rating int,
  company text,
  sort_order int not null default 0,
  is_published boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists site_faqs (
  id uuid primary key default gen_random_uuid(),
  question text not null,
  answer text not null,
  sort_order int not null default 0,
  is_published boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists calendar_events (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  description text,
  start_at timestamptz not null,
  end_at timestamptz not null,
  location text,
  meeting_link text,
  status text not null default 'available',
  created_by uuid references admin_users(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists bookings (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  email text not null,
  phone text,
  company text,
  service text,
  budget text,
  message text,
  preferred_date date,
  preferred_time text,
  status text not null default 'new',
  source text not null default 'website',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists contact_submissions (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  email text not null,
  phone text,
  company text,
  service text,
  budget text,
  message text,
  attachment_name text,
  attachment_content_type text,
  attachment_base64 text,
  status text not null default 'new',
  admin_reply text,
  replied_at timestamptz,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists idx_projects_featured on projects(is_featured, feature_order);
create index if not exists idx_calendar_events_start_at on calendar_events(start_at);
create index if not exists idx_bookings_created_at on bookings(created_at desc);
create index if not exists idx_contact_submissions_created_at on contact_submissions(created_at desc);

-- Permissions + owner role + admin user
insert into permissions(key, label) values ('dashboard', 'Dashboard') on conflict (key) do update set label = excluded.label;
insert into permissions(key, label) values ('users', 'User Management') on conflict (key) do update set label = excluded.label;
insert into permissions(key, label) values ('roles', 'Roles and Permissions') on conflict (key) do update set label = excluded.label;
insert into permissions(key, label) values ('calendar', 'Calendar') on conflict (key) do update set label = excluded.label;
insert into permissions(key, label) values ('bookings', 'Bookings and Contact Submissions') on conflict (key) do update set label = excluded.label;
insert into permissions(key, label) values ('projects', 'Projects') on conflict (key) do update set label = excluded.label;
insert into permissions(key, label) values ('teams', 'Teams') on conflict (key) do update set label = excluded.label;
insert into permissions(key, label) values ('blogs', 'Blogs') on conflict (key) do update set label = excluded.label;
insert into permissions(key, label) values ('systems', 'Ready-Made Systems') on conflict (key) do update set label = excluded.label;

insert into roles(name, description, is_system)
values ('Owner', 'Full platform control', true)
on conflict (name) do update set description = excluded.description;


insert into role_permissions(role_id, permission_key, can_read, can_write, can_delete)
select r.id, p.key, true, true, true
from roles r
cross join permissions p
where r.name = 'Owner'
on conflict (role_id, permission_key)
do update set can_read = excluded.can_read, can_write = excluded.can_write, can_delete = excluded.can_delete, updated_at = now();


insert into admin_users(email, full_name, password_hash, role_id, is_active)
select 'admin@progrex.cloud', 'System Admin', crypt('ChangeMe123!', gen_salt('bf', 12)), r.id, true
from roles r
where r.name = 'Owner'
on conflict (email)
do update set full_name = excluded.full_name, password_hash = excluded.password_hash, role_id = excluded.role_id, is_active = true, updated_at = now();

-- Content seed (services, projects, team, systems, testimonials, faqs, blogs)
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('custom-software-development', 'Custom Software Development', 'Tailored software solutions engineered to solve your unique business challenges at any scale. From startup MVPs to enterprise systems, we turn your vision into clean, maintainable, and production-ready code.', '🖥️', 'from-[#3A0CA3] to-[#4361EE]', '{"description":"We design, develop, and deploy custom software solutions that align perfectly with your business processes. From enterprise resource planning to specialized tools, we bring your vision to life with clean, scalable code.","process":[{"step":1,"title":"Discovery & Analysis","desc":"We deep-dive into your requirements, processes, and goals."},{"step":2,"title":"System Design","desc":"Architecture planning, database schema, and tech stack selection."},{"step":3,"title":"Agile Development","desc":"Iterative sprints with regular demos and feedback loops."},{"step":4,"title":"QA & Testing","desc":"Comprehensive unit, integration, and performance testing."},{"step":5,"title":"Deployment","desc":"CI/CD pipeline setup and production deployment."},{"step":6,"title":"Maintenance","desc":"Ongoing support, updates, and feature enhancements."}],"technologies":["React","Next.js","Node.js","Python","PostgreSQL","MongoDB","Docker","AWS","Redis","GraphQL"],"deliverables":["Complete source code with inline documentation","Database schema, ERD & data dictionary","REST / GraphQL API documentation","CI/CD pipeline configuration","Production deployment & environment setup","Post-launch bug fixes (30-day warranty)"],"idealFor":[{"title":"Startups & SMEs","desc":"Building a new product or internal tool from the ground up with a reliable technical partner."},{"title":"Enterprise Teams","desc":"Modernizing legacy systems or extending business-critical capabilities without disrupting operations."},{"title":"Product Companies","desc":"Scaling or rebuilding core platform features with clean, maintainable, production-ready code."}],"highlights":[{"icon":"Layers","label":"Full-Stack Delivery","desc":"Front-end, back-end, database, and DevOps — all designed and built under one roof."},{"icon":"ShieldCheck","label":"IP Ownership","desc":"You own 100% of the source code and all intellectual property upon project completion."},{"icon":"RefreshCw","label":"Agile Process","desc":"Weekly sprints, demos, and structured feedback loops keep you in full control throughout."},{"icon":"Headphones","label":"Post-Launch Support","desc":"30-day free bug-fix warranty and optional long-term maintenance retainer plans."}],"faqs":[{"q":"How much does custom software cost?","a":"Pricing depends on scope and complexity. Simple internal tools typically start at ₱50,000–₱120,000, while full enterprise platforms can range from ₱300,000 to ₱2,000,000+. We provide a detailed project estimate after the discovery phase."},{"q":"How long does a custom project take?","a":"Timelines vary by complexity — typically 3–12 months for enterprise projects, 4–8 weeks for smaller internal tools."},{"q":"Do you sign NDAs?","a":"Absolutely. We sign an NDA before any project discussion to protect your idea and business details."},{"q":"Will I own the source code?","a":"Yes. Upon full payment, all intellectual property and source code belong entirely to you."}]}'::jsonb, 0, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('web-development', 'Web Development', 'High-performance, visually stunning websites and web apps built for conversion and scale. Our engineers craft pixel-perfect UIs backed by rock-solid APIs, consistently fast load times, seamless user experiences, and scalable architectures designed to drive measurable results.', '🌐', 'from-[#560BAD] to-[#831DC6]', '{"description":"From corporate websites to complex SaaS platforms, we build fast, accessible, and SEO-optimized web experiences. Our front-end engineers craft pixel-perfect UIs while our back-end experts ensure rock-solid APIs.","process":[{"step":1,"title":"Strategy & Wireframing","desc":"User flows, sitemap, and wireframe design."},{"step":2,"title":"UI/UX Design","desc":"High-fidelity mockups with your brand system."},{"step":3,"title":"Front-End Development","desc":"React/Next.js powered with Tailwind CSS."},{"step":4,"title":"Back-End & APIs","desc":"RESTful or GraphQL APIs with secure authentication."},{"step":5,"title":"Performance Optimization","desc":"Core Web Vitals tuning, lazy loading, CDN."},{"step":6,"title":"Launch & SEO","desc":"Production deployment with SEO and analytics setup."}],"technologies":["Next.js","React","Tailwind CSS","TypeScript","Node.js","Prisma","Vercel","PostgreSQL","Stripe","Framer Motion"],"deliverables":["Responsive, pixel-perfect web app or website","CMS or admin dashboard (if applicable)","SEO-optimized page structure & meta setup","Analytics integration (GA4 / Plausible)","Performance-tuned production build","Hosting, domain, and DNS configuration"],"idealFor":[{"title":"Businesses & Brands","desc":"Need a high-converting, professional online presence that authentically reflects your brand."},{"title":"SaaS Founders","desc":"Building a web-based platform with subscriptions, user dashboards, and third-party API integrations."},{"title":"E-commerce Operators","desc":"Launching or upgrading an online store with modern UX, optimized checkout, and payment flows."}],"highlights":[{"icon":"Gauge","label":"Performance First","desc":"Core Web Vitals optimized — Lighthouse scores above 90 across performance, SEO, and accessibility."},{"icon":"Globe","label":"SEO Ready","desc":"Structured data, semantic HTML, and meta architecture built in from the very first page."},{"icon":"Smartphone","label":"Mobile-First Design","desc":"Every interface is designed and thoroughly tested on mobile, tablet, and desktop."},{"icon":"Lock","label":"Secure by Default","desc":"HTTPS, input validation, rate limiting, and secure authentication on every project."}],"faqs":[{"q":"How much does a website cost?","a":"Pricing varies depending on complexity. A simple landing page starts at around ₱15,000–₱40,000, a corporate website with CMS typically runs ₱50,000–₱150,000, and full-featured web applications or SaaS platforms start at ₱200,000 and up. We provide a fixed quote before any work begins."},{"q":"Will the website be mobile-friendly?","a":"Every site we build is mobile-first and tested thoroughly across phones, tablets, and desktops."},{"q":"Do you provide hosting?","a":"We can set up and manage hosting on Vercel, AWS, or your preferred provider — included in most project packages."},{"q":"Can you redesign my existing site?","a":"Yes. We offer full redesigns and UX overhauls while carefully preserving your existing SEO equity."}]}'::jsonb, 1, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('mobile-app-development', 'Mobile App Development', 'Native and cross-platform mobile apps that deliver exceptional user experiences on iOS and Android. Built with React Native or Flutter, every app is designed for engagement, retention, and long-term growth.', '📱', 'from-[#831DC6] to-[#CFA3EA]', '{"description":"We build iOS and Android applications using React Native and Flutter for cross-platform efficiency, or Swift/Kotlin for native performance. Every app is designed for engagement, retention, and scalability.","process":[{"step":1,"title":"Market & User Research","desc":"Competitor analysis and user persona definition."},{"step":2,"title":"UX Prototyping","desc":"Interactive prototypes for user flow validation."},{"step":3,"title":"App Development","desc":"React Native or Flutter cross-platform development."},{"step":4,"title":"Backend Integration","desc":"API integration, push notifications, offline sync."},{"step":5,"title":"App Store Submission","desc":"iOS App Store and Google Play deployment."},{"step":6,"title":"Analytics & Updates","desc":"Crash reporting, analytics, and iterative updates."}],"technologies":["React Native","Flutter","Swift","Kotlin","Firebase","Node.js","AWS","Expo","Redux","SQLite"],"deliverables":["Published iOS & Android app (App Store + Google Play)","App Store listing assets & screenshots","Push notification setup & configuration","Analytics & crash reporting integration","API backend documentation","Post-submission support (14 days)"],"idealFor":[{"title":"Consumer Product Startups","desc":"Launching a mobile-first product targeting end users on both iOS and Android."},{"title":"Businesses with Field Teams","desc":"Need offline-capable, GPS-aware, or hardware-connected mobile tools for staff in the field."},{"title":"SaaS Companies","desc":"Adding a polished mobile client alongside an existing web platform or backend API."}],"highlights":[{"icon":"Smartphone","label":"Cross-Platform Efficiency","desc":"React Native & Flutter deliver native-quality UX at a fraction of the cost of two native builds."},{"icon":"WifiOff","label":"Offline Support","desc":"Local storage, sync queues, and conflict resolution for robust offline-first apps."},{"icon":"BellRing","label":"Push Notifications","desc":"Targeted campaigns, transactional alerts, and scheduled reminders built in from the start."},{"icon":"BarChart2","label":"Built-In Analytics","desc":"Event tracking, conversion funnels, and retention metrics instrumented from day one."}],"faqs":[{"q":"How much does a mobile app cost?","a":"Cost depends heavily on features and platform. A simple cross-platform app typically starts at ₱80,000–₱200,000, while apps with custom backends, real-time features, or complex workflows range from ₱300,000 to ₱1,000,000+. Complexity, integrations, and target platforms are the main cost drivers."},{"q":"Cross-platform or native?","a":"We recommend cross-platform (React Native/Flutter) for most projects — it delivers near-native performance at a significantly lower cost. Native development is only recommended when platform-specific hardware features are required."},{"q":"Do you handle App Store submissions?","a":"Yes — we manage the full submission and review process for both the Apple App Store and Google Play Store."}]}'::jsonb, 2, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('system-integration', 'System Integration', 'Seamlessly connect your existing systems, APIs, and third-party platforms for unified, automated operations. We eliminate data silos and bridge ERPs, CRMs, payment gateways, and legacy systems into a single ecosystem.', '🔗', 'from-[#4361EE] to-[#3A0CA3]', '{"description":"Break down data silos and achieve operational efficiency by integrating disparate systems. We connect ERPs, CRMs, payment gateways, third-party APIs, and legacy systems into a unified, automated ecosystem.","process":[{"step":1,"title":"Systems Audit","desc":"Map all existing systems, data flows, and integration points."},{"step":2,"title":"Integration Design","desc":"Define API contracts, middleware, and data transformation rules."},{"step":3,"title":"Development","desc":"Build connectors, webhooks, and middleware services."},{"step":4,"title":"Testing","desc":"End-to-end integration and data integrity testing."},{"step":5,"title":"Deployment","desc":"Zero-downtime deployment with rollback strategies."},{"step":6,"title":"Monitoring","desc":"Real-time monitoring, alerting, and error handling."}],"technologies":["REST APIs","GraphQL","Webhooks","Zapier","Make.com","Kafka","RabbitMQ","AWS Lambda","n8n","Salesforce API"],"deliverables":["Integration architecture & data flow document","Custom API connectors & middleware","Data transformation and mapping rules","Error handling, retry logic & dead-letter queues","End-to-end integration test results","Live monitoring dashboard & alert setup"],"idealFor":[{"title":"Growing Businesses","desc":"Using multiple SaaS tools that do not sync, creating manual data silos and costly double-entry work."},{"title":"Enterprises with Legacy Systems","desc":"Needing to connect old on-premise software with modern cloud platforms and REST APIs."},{"title":"Operations Teams","desc":"Spending hours on data exports, copy-paste workflows, and manual consolidation cycles every week."}],"highlights":[{"icon":"Plug","label":"Any-to-Any Integration","desc":"REST, GraphQL, SOAP, webhooks, FTP — we bridge virtually any protocol combination."},{"icon":"ShieldCheck","label":"Secure Data Transit","desc":"OAuth 2.0, API key rotation, and TLS-encrypted channels on every integration."},{"icon":"Activity","label":"Real-Time Monitoring","desc":"Live integration health dashboards with automatic failure alerting and retry logic."},{"icon":"RefreshCw","label":"Zero-Downtime Rollout","desc":"Gradual cutover strategies with rollback plans ensure business continuity during go-live."}],"faqs":[{"q":"How much does system integration cost?","a":"Pricing depends on the number of systems and the complexity of data flows. Simple two-system integrations typically start at ₱30,000–₱80,000, while multi-platform enterprise integrations commonly range from ₱150,000 to ₱500,000+. We assess your current systems and provide a scoped estimate after audit."},{"q":"Can you integrate legacy systems?","a":"Yes, we specialize in bridging modern cloud platforms with legacy on-premise software using adapters, middleware, and protocol translation layers."},{"q":"What about data security?","a":"All integrations are secured with OAuth 2.0, API key management, TLS encryption, and strict role-based access on every data channel."}]}'::jsonb, 3, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('academic-capstone-system-development', 'Capstone System Development', 'Professional, fully functional capstone and thesis systems for students — delivered on time, every time. We build complete, documented, and demo-ready systems that exceed academic panel requirements.', '🎓', 'from-[#3A0CA3] to-[#831DC6]', '{"description":"We help students build impressive, fully-functional capstone and thesis systems. From inventory management to healthcare systems, we build complete, documented, and presentable systems that exceed academic requirements.","process":[{"step":1,"title":"Requirements Gathering","desc":"Review your thesis proposal and define system scope."},{"step":2,"title":"System Design","desc":"ERD, DFD, use case diagrams, and wireframes."},{"step":3,"title":"Development","desc":"Full system development with documentation."},{"step":4,"title":"Testing","desc":"Bug-free, tested system ready for demonstration."},{"step":5,"title":"Documentation","desc":"Complete technical and user documentation."},{"step":6,"title":"Presentation Support","desc":"Practice walkthrough for your panel defense."}],"technologies":["PHP/Laravel","MySQL","React","Python","Java","C#/.NET","Bootstrap","Vue.js","Firebase","SQLite"],"deliverables":["Fully functional, demo-ready system","Commented and organized source code","Technical documentation (ERD, DFD, use cases)","User manual and admin guide","Presentation walkthrough and rehearsal session","Bug-free demo build ready for panel defense"],"idealFor":[{"title":"Graduating Students","desc":"Need a complete, documented, and demo-ready capstone or thesis system to pass panel review."},{"title":"Student Project Groups","desc":"Teams whose scope exceeds their current technical skills and need professional-grade development."},{"title":"Deadline-Pressured Students","desc":"Panel defense approaching with development behind schedule — rush delivery is available."}],"highlights":[{"icon":"Clock","label":"Fast Delivery","desc":"Rush orders accepted — most capstone systems are completed within 2 to 4 weeks."},{"icon":"BookOpen","label":"Full Documentation","desc":"Complete technical docs, ERD, DFD, use case diagrams, and user manuals included."},{"icon":"GraduationCap","label":"Panel-Ready Builds","desc":"Clean UI, working features, and demo scenarios walkthroughs rehearsed with you before defense."},{"icon":"ShieldCheck","label":"NDA Protected","desc":"Your project idea and all project details are handled with complete confidentiality under NDA."}],"faqs":[{"q":"How much does a capstone system cost?","a":"Pricing depends on the system type and complexity. Basic single-module systems start at ₱8,000–₱15,000, while multi-module systems with mobile apps or advanced features typically range from ₱20,000 to ₱45,000+. Rush delivery and full documentation are available for all tiers."},{"q":"Is this plagiarism?","a":"No. Every system is custom-built from scratch based on your thesis topic and requirements. We also walk you through the system so you fully understand and can confidently present it to your panel."},{"q":"How fast can you deliver?","a":"Rush delivery is available. Most capstone systems are completed within 2–4 weeks, depending on scope and your submission deadline."}]}'::jsonb, 4, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('it-consulting-infrastructure', 'IT Consulting / Infrastructure', 'Strategic technology consulting and infrastructure setup to optimize your business operations. From cloud migrations to DevOps strategy and security hardening, we turn complex IT decisions into clear, ROI-driven action plans.', '⚙️', 'from-[#560BAD] to-[#4361EE]', '{"description":"Our IT consultants provide expert guidance on technology strategy, cloud migration, DevOps implementation, cybersecurity, and infrastructure optimization. We help businesses make the right technology decisions.","process":[{"step":1,"title":"IT Audit","desc":"Assess current infrastructure, security, and processes."},{"step":2,"title":"Strategy Development","desc":"Roadmap for technology improvements and investments."},{"step":3,"title":"Implementation Planning","desc":"Detailed execution plan with timelines and KPIs."},{"step":4,"title":"Execution","desc":"Hands-on implementation and configuration."},{"step":5,"title":"Training","desc":"Team training and knowledge transfer."},{"step":6,"title":"Ongoing Support","desc":"Managed services and continuous optimization."}],"technologies":["AWS","Azure","Google Cloud","Docker","Kubernetes","Terraform","Linux","Nginx","Cloudflare","Datadog"],"deliverables":["Current-state IT audit report","Prioritized technology roadmap","Implementation plan with KPIs and milestones","Cloud architecture diagrams","Security and compliance recommendations document","Team training and knowledge transfer sessions"],"idealFor":[{"title":"Growing SMEs","desc":"Scaling operations rapidly and needing a clear, actionable technology strategy aligned to budget."},{"title":"Companies Migrating to Cloud","desc":"Transitioning from costly on-premise infrastructure to AWS, Azure, or Google Cloud."},{"title":"Teams with Security Concerns","desc":"Need a comprehensive audit and hardening of their IT environment before a compliance review."}],"highlights":[{"icon":"Map","label":"Technology Roadmap","desc":"A clear, prioritized roadmap aligned to your business goals, constraints, and budget reality."},{"icon":"Cloud","label":"Multi-Cloud Expertise","desc":"Deep hands-on experience across AWS, Azure, and GCP for migrations and architecture design."},{"icon":"Shield","label":"Security-First Lens","desc":"Every recommendation is evaluated through a cybersecurity and regulatory compliance lens."},{"icon":"Users","label":"Knowledge Transfer","desc":"We train your team thoroughly so you are never dependent on external expertise long-term."}],"faqs":[{"q":"How much does IT consulting cost?","a":"Consulting is available on a day-rate or project basis. Day rates typically range from ₱5,000–₱20,000 depending on the engagement. Project-based consulting — such as cloud migration planning or a full IT audit — commonly ranges from ₱40,000 to ₱200,000+, depending on scope and infrastructure size."},{"q":"Do you offer cloud migration?","a":"Yes. We plan and execute full cloud migrations to AWS, Azure, or GCP — with minimal downtime and a staged rollback strategy."},{"q":"Can you help with cybersecurity?","a":"Yes. We offer security audits, threat modeling, penetration testing recommendations, and end-to-end security hardening for your infrastructure."}]}'::jsonb, 5, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('hardware-integration', 'Hardware Integration', 'Bridge the physical and digital worlds by connecting hardware devices, sensors, and embedded systems directly to your software. We design end-to-end IoT solutions that enable real-time monitoring, remote control, and automated data collection from your physical infrastructure.', '🔌', 'from-[#0EA5E9] to-[#4361EE]', '{"description":"We design and implement IoT architectures that connect physical hardware — from industrial sensors and microcontrollers to smart devices and embedded systems — to cloud and web platforms. Our team handles firmware communication, protocol translation, real-time data pipelines, and dashboard visualization.","process":[{"step":1,"title":"Hardware Audit","desc":"Evaluate existing devices, sensors, and communication protocols."},{"step":2,"title":"Architecture Design","desc":"Design the IoT stack: device layer, gateway, cloud, and dashboard."},{"step":3,"title":"Firmware & Protocol","desc":"Configure device firmware and communication protocols (MQTT, HTTP, BLE, etc.)."},{"step":4,"title":"Cloud Integration","desc":"Connect hardware to cloud platforms with secure, reliable data pipelines."},{"step":5,"title":"Dashboard & Alerts","desc":"Build real-time monitoring dashboards and automated alerting."},{"step":6,"title":"Support & Scaling","desc":"Ongoing device management, OTA updates, and fleet scaling."}],"technologies":["Arduino","Raspberry Pi","MQTT","AWS IoT","Node-RED","Firebase","Python","C/C++","LoRaWAN","Modbus"],"deliverables":["IoT system architecture document","Configured device firmware & communication protocols","Cloud data ingestion pipeline","Real-time monitoring dashboard","Automated alert & notification system","OTA (over-the-air) update mechanism"],"idealFor":[{"title":"Industrial Operators","desc":"Monitoring machines, sensors, and production lines in real time from a centralized dashboard."},{"title":"Smart Building Owners","desc":"Automating HVAC, access control, energy metering, and facility management systems."},{"title":"Logistics & Fleet Companies","desc":"Tracking vehicles, assets, and cargo with real-time GPS positioning and telemetry."}],"highlights":[{"icon":"Cpu","label":"Protocol Agnostic","desc":"MQTT, HTTP, BLE, LoRaWAN, Modbus — we work with any hardware communication standard."},{"icon":"Activity","label":"Real-Time Pipelines","desc":"Live data streams from edge devices to cloud dashboards with minimal latency."},{"icon":"RefreshCw","label":"OTA Updates","desc":"Push firmware updates to your entire deployed device fleet remotely and safely at scale."},{"icon":"ShieldCheck","label":"Secure by Design","desc":"Device authentication, encrypted channels, and network segmentation built into every solution."}],"faqs":[{"q":"How much does hardware/IoT integration cost?","a":"Cost varies widely based on the number of devices, protocols, and dashboard complexity. A basic IoT integration project typically starts at ₱50,000–₱150,000, while full industrial fleet setups with custom dashboards and cloud pipelines commonly range from ₱250,000 to ₱700,000+, depending on scale and requirements."},{"q":"Do you work with existing hardware?","a":"Yes. We integrate with virtually any hardware that supports standard communication protocols such as MQTT, HTTP, Modbus, BLE, or LoRaWAN."},{"q":"Can you build the physical device too?","a":"We partner with trusted hardware engineers and electronics prototyping firms for full custom device design and manufacturing when needed."}]}'::jsonb, 6, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('ai-machine-learning', 'AI & Machine Learning', 'Harness the power of artificial intelligence to automate decisions, uncover hidden insights, and build smarter products at scale. From predictive analytics and computer vision to LLM-powered chatbots and custom model training, we bring AI from concept into production.', '🤖', 'from-[#7C3AED] to-[#0EA5E9]', '{"description":"We develop custom AI and machine learning solutions that transform raw data into measurable competitive advantage. Our data scientists and ML engineers build, train, evaluate, and deploy models that solve real business problems — from intelligent recommendation engines to automated quality inspection systems.","process":[{"step":1,"title":"Problem Framing","desc":"Define the business problem and evaluate AI applicability."},{"step":2,"title":"Data Strategy","desc":"Data collection, cleaning, labeling, and pipeline design."},{"step":3,"title":"Model Development","desc":"Train, evaluate, and iterate on ML/AI models."},{"step":4,"title":"Integration","desc":"Embed models into your application via REST APIs or SDKs."},{"step":5,"title":"Deployment","desc":"Production deployment with monitoring, versioning, and retraining pipelines."},{"step":6,"title":"Monitoring & Retraining","desc":"Track model performance and retrain on new data over time."}],"technologies":["Python","TensorFlow","PyTorch","Scikit-learn","OpenAI","LangChain","Hugging Face","FastAPI","MLflow","AWS SageMaker"],"deliverables":["Trained, evaluated & versioned ML model","REST API endpoint for model inference","Data training pipeline & annotated notebooks","Model performance metrics dashboard","Automated retraining schedule & triggers","Model documentation & model cards"],"idealFor":[{"title":"Data-Rich Businesses","desc":"Have large datasets and need AI to extract patterns, insights, and drive automated decisions."},{"title":"Product Companies","desc":"Want intelligent features — recommendations, predictions, or NLP — embedded in their product."},{"title":"Operations Teams","desc":"Seeking to automate quality inspection, document processing, or anomaly detection workflows."}],"highlights":[{"icon":"Brain","label":"Custom Model Training","desc":"We train models on your data — not one-size-fits-all solutions that ignore your domain."},{"icon":"Zap","label":"Production-Ready APIs","desc":"Models deployed as scalable, versioned REST APIs with performance monitoring built in."},{"icon":"Database","label":"Data Pipeline Included","desc":"From raw data ingestion and labeling to feature engineering, validation, and storage."},{"icon":"TrendingUp","label":"Continuous Improvement","desc":"Automated retraining pipelines keep your models accurate as new data flows in."}],"faqs":[{"q":"How much does an AI/ML project cost?","a":"Pricing depends on model complexity, data availability, and deployment requirements. A basic AI feature or chatbot typically starts at ₱80,000–₱200,000. Custom-trained models with full MLOps pipelines for enterprise use commonly range from ₱350,000 to ₱1,200,000+. We scope each project after an initial data and requirements assessment."},{"q":"Do we need a large dataset?","a":"Not always. We leverage pre-trained models, transfer learning, and data augmentation techniques to deliver strong results even with limited data — depending on the use case."},{"q":"Can you build a chatbot trained on our data?","a":"Yes. We build RAG-based chatbots and fine-tuned LLM applications powered by your own documents, knowledge base, or internal data."}]}'::jsonb, 7, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('business-automation', 'Business Automation', 'Eliminate repetitive manual processes and reclaim thousands of hours every year through intelligent, reliable workflow automation. We design and build custom automation pipelines — from RPA and API integrations to AI-driven decision workflows — so your team focuses on high-value work.', '⚡', 'from-[#4361EE] to-[#560BAD]', '{"description":"We analyze your business workflows and identify automation opportunities — then build custom solutions that eliminate bottlenecks, reduce errors, and accelerate throughput. From document processing and report generation to multi-step approval workflows, we automate it all without disrupting existing operations.","process":[{"step":1,"title":"Process Mapping","desc":"Document and analyze all manual workflows and bottlenecks."},{"step":2,"title":"Automation Design","desc":"Design the automation architecture — RPA, APIs, or custom tools."},{"step":3,"title":"Development","desc":"Build and test automation scripts, bots, and workflow engines."},{"step":4,"title":"Integration","desc":"Connect to your existing software stack and data sources."},{"step":5,"title":"Testing & Rollout","desc":"UAT, parallel testing, and phased production rollout."},{"step":6,"title":"Monitoring","desc":"Logs, alerts, and dashboards to ensure automation reliability."}],"technologies":["n8n","Make.com","Zapier","Python","Node.js","Power Automate","Selenium","Apache Airflow","REST APIs","PostgreSQL"],"deliverables":["Fully built automation workflows & scripts","API integration connectors","Error logging, retry logic & failure alerts","Operations monitoring dashboard","Detailed process documentation","Handover training session for your team"],"idealFor":[{"title":"Operations-Heavy Teams","desc":"Staff spending hours daily on repetitive data entry, status updates, or approval routing tasks."},{"title":"Finance & HR Departments","desc":"Automating payroll runs, invoicing, employee onboarding, and compliance reporting cycles."},{"title":"Scaling Businesses","desc":"Growing throughput and output volume without proportionally increasing headcount or overhead."}],"highlights":[{"icon":"Zap","label":"End-to-End Automation","desc":"From trigger to final output — zero manual steps required once automation is deployed."},{"icon":"PieChart","label":"ROI Focused","desc":"We quantify time saved and cost reduction before and after each automation is built."},{"icon":"GitMerge","label":"Non-Invasive Integration","desc":"Hooks into your existing software stack via APIs — no system overhauls or migrations needed."},{"icon":"Bell","label":"Smart Alerting","desc":"Instant notifications when an automation fails or needs a human decision to continue."}],"faqs":[{"q":"How much does business automation cost?","a":"Cost depends on the number of workflows, tools involved, and volume of transactions. A single automated workflow typically starts at ₱25,000–₱70,000. Full-suite automation across multiple departments commonly ranges from ₱120,000 to ₱500,000+, depending on complexity and integrations required."},{"q":"Which processes are best for automation?","a":"Repetitive, rule-based, high-volume tasks with predictable inputs and outputs are ideal — such as data entry, report generation, invoicing, approvals, and notifications."},{"q":"Will automation break my existing systems?","a":"No. We design all automation non-invasively — hooking into your existing software via APIs and webhooks without touching or modifying core systems."}]}'::jsonb, 8, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('deployment-hosting-services', 'Deployment & Hosting', 'Take your application from code to production with a reliable, secure, and auto-scaling infrastructure setup built for real-world traffic. We configure CI/CD pipelines, cloud environments, container orchestration, and continuous monitoring so your systems stay fast, available, and automatically updated.', '🚀', 'from-[#560BAD] to-[#0EA5E9]', '{"description":"We handle the full deployment lifecycle — from environment provisioning and containerization to CI/CD automation and production hardening. Whether you are deploying a simple web app or a distributed microservices architecture, we ensure zero-downtime releases, auto-scaling, and comprehensive observability.","process":[{"step":1,"title":"Infrastructure Audit","desc":"Assess your current setup and define deployment targets."},{"step":2,"title":"Environment Setup","desc":"Configure cloud environments: dev, staging, and production."},{"step":3,"title":"Containerization","desc":"Dockerize your application for portability and consistency."},{"step":4,"title":"CI/CD Pipeline","desc":"Automated build, test, and deploy pipelines with rollback support."},{"step":5,"title":"Security Hardening","desc":"SSL, secrets management, firewall rules, and IAM policies."},{"step":6,"title":"Monitoring & Alerts","desc":"Uptime monitoring, log aggregation, and incident alerting."}],"technologies":["Docker","Kubernetes","AWS","Google Cloud","Vercel","GitHub Actions","Terraform","Nginx","Cloudflare","Datadog"],"deliverables":["Cloud environment setup (dev / staging / prod)","Fully containerized application (Docker)","Automated CI/CD pipeline with rollback support","SSL, domain, and DNS configuration","Monitoring, logging & uptime alert dashboards","Runbook and infrastructure handover documentation"],"idealFor":[{"title":"Development Teams","desc":"Built the app but need expert help getting it to production reliably, securely, and repeatably."},{"title":"Scale-Up Companies","desc":"Outgrowing shared hosting and needing auto-scaling cloud infrastructure for real-world traffic."},{"title":"DevOps-Less Teams","desc":"No in-house DevOps expertise and needing a full pipeline built and handed over with training."}],"highlights":[{"icon":"Rocket","label":"Zero-Downtime Deploys","desc":"Blue-green and rolling deployments ensure your users never experience downtime during releases."},{"icon":"ShieldCheck","label":"Security Hardened","desc":"IAM policies, secrets management, firewall rules, and SSL configured from day one."},{"icon":"Gauge","label":"Auto-Scaling","desc":"Scale up instantly on traffic spikes and back down automatically — pay for only what you use."},{"icon":"Activity","label":"Full Observability","desc":"Logs, metrics, distributed traces, and uptime alerts wired across every layer of your stack."}],"faqs":[{"q":"How much does deployment and DevOps setup cost?","a":"Pricing depends on stack complexity and cloud provider. A straightforward cloud setup with CI/CD pipeline typically starts at ₱20,000–₱60,000. Full containerized deployments with Kubernetes, monitoring, and multi-environment pipelines commonly range from ₱80,000 to ₱250,000+, depending on scale and requirements."},{"q":"Which cloud provider do you recommend?","a":"It depends on your needs, team familiarity, and budget — we work with AWS, GCP, and Azure and make recommendations based on your specific scale, cost targets, and existing stack."},{"q":"Can you manage our existing deployment?","a":"Yes. We offer managed DevOps retainer services including ongoing CI/CD pipeline management, infrastructure cost optimization, and incident response."}]}'::jsonb, 9, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('ui-ux-design', 'UI/UX Design & Prototyping', 'Great software starts with great design — we craft intuitive, visually compelling user experiences grounded in user research and validated through real testing. From wireframes and interactive prototypes to production-ready design systems, every interface we design is built to feel effortless and convert.', '🎨', 'from-[#831DC6] to-[#CFA3EA]', '{"description":"Our design team blends aesthetics with usability to create digital experiences that users love and businesses rely on. We follow a research-driven process — user interviews, competitive analysis, information architecture, and iterative testing — to ensure every design decision is validated before a line of code is written.","process":[{"step":1,"title":"Research","desc":"User research, persona creation, and competitive analysis."},{"step":2,"title":"Information Architecture","desc":"Sitemap, user flows, and content hierarchy design."},{"step":3,"title":"Wireframing","desc":"Low and mid-fidelity wireframes for rapid concept validation."},{"step":4,"title":"UI Design","desc":"High-fidelity mockups with a branded design system."},{"step":5,"title":"Prototyping","desc":"Interactive Figma prototypes for stakeholder and user testing."},{"step":6,"title":"Handoff","desc":"Developer-ready assets, annotations, and component specifications."}],"technologies":["Figma","Adobe XD","Framer","Photoshop","Illustrator","Lottie","Zeplin","Storybook","Tailwind CSS","Framer Motion"],"deliverables":["User research report & personas","Sitemap & user flow diagrams","Low and high-fidelity wireframes","Interactive Figma prototype","Design system & component library","Developer handoff package (specs, assets, annotations)"],"idealFor":[{"title":"Founders & Product Managers","desc":"Need to validate product concepts and communicate a clear vision to stakeholders before development."},{"title":"Development Teams","desc":"Code-ready but lack design expertise for a polished, user-tested, and conversion-optimized interface."},{"title":"Established Businesses","desc":"Existing product suffering from UX friction, poor retention, or brand inconsistency that needs a redesign."}],"highlights":[{"icon":"Users","label":"Research-Driven Design","desc":"Every decision is backed by user interviews, competitive analysis, and iterative usability testing."},{"icon":"Palette","label":"Full Design System","desc":"Reusable components, design tokens, and guidelines your dev team can build from and scale forever."},{"icon":"MousePointer","label":"Interactive Prototypes","desc":"Fully clickable Figma prototypes for real user testing and polished stakeholder presentations."},{"icon":"Code2","label":"Dev-Ready Handoff","desc":"Annotated specs, exported assets, and component docs that eliminate developer guesswork."}],"faqs":[{"q":"How much does UI/UX design cost?","a":"Pricing depends on the scope and deliverables. Wireframes and basic prototypes typically start at ₱15,000–₱40,000. A full design engagement — including user research, high-fidelity UI, interactive prototypes, and a design system — commonly ranges from ₱60,000 to ₱200,000+, depending on complexity and number of screens."},{"q":"Do you offer design-only engagements?","a":"Yes. We provide UI/UX design as a fully standalone service — no development required — delivering Figma files, design tokens, and developer-ready component specs."},{"q":"Will you design for both web and mobile?","a":"Absolutely. We design responsive web interfaces and native mobile UIs simultaneously within a single unified design system, ensuring consistency across all platforms."}]}'::jsonb, 10, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into services(slug, title, short_desc, icon, color, details, sort_order, is_published) values ('cybersecurity-data-protection', 'Cybersecurity & Data Protection', 'Protect your systems, data, and users with a proactive, security-first approach embedded into every layer of your application. We conduct security audits, implement authentication and encryption best practices, and guide your team to eliminate vulnerabilities before they become costly threats.', '🛡️', 'from-[#3A0CA3] to-[#4361EE]', '{"description":"We provide comprehensive cybersecurity services for software applications and IT infrastructure — from threat modeling and penetration testing to secure code review and compliance guidance. Our security engineers work alongside your team to build resilient systems that protect sensitive data and maintain user trust.","process":[{"step":1,"title":"Threat Modeling","desc":"Identify attack surfaces, threat vectors, and risk scenarios."},{"step":2,"title":"Security Audit","desc":"Code review, dependency scanning, and configuration analysis."},{"step":3,"title":"Hardening","desc":"Apply security fixes, encryption, and access control improvements."},{"step":4,"title":"Penetration Testing","desc":"Controlled ethical hacking to discover exploitable vulnerabilities."},{"step":5,"title":"Compliance Review","desc":"Guidance on GDPR, HIPAA, PCI-DSS, and SOC2 requirements."},{"step":6,"title":"Training & Policy","desc":"Security awareness training and internal policy documentation."}],"technologies":["OWASP","JWT","OAuth 2.0","SSL/TLS","AWS Security Hub","HashiCorp Vault","Snyk","CORS","CSP","2FA/MFA"],"deliverables":["Vulnerability assessment & risk-rated findings report","Threat model document","Security hardening implementation","Penetration test results & reproduction steps","Compliance checklist (GDPR / HIPAA / PCI-DSS)","Security awareness training materials for your team"],"idealFor":[{"title":"SaaS & Web Applications","desc":"Handling user data, payments, or sensitive business records that must be rigorously protected."},{"title":"Regulated Industries","desc":"Operating under GDPR, HIPAA, or PCI-DSS compliance requirements needing validation and guidance."},{"title":"Post-Incident Teams","desc":"Recovering from a breach or failed security audit and needing a rapid, comprehensive overhaul."}],"highlights":[{"icon":"Shield","label":"Proactive Security","desc":"We identify and remediate vulnerabilities before attackers do — not after a costly breach."},{"icon":"FileSearch","label":"Detailed Reporting","desc":"Every finding documented with severity rating, reproduction steps, and clear remediation guidance."},{"icon":"Lock","label":"Compliance Guidance","desc":"Practical, actionable paths to GDPR, HIPAA, and PCI-DSS compliance — not just theory."},{"icon":"Eye","label":"Ongoing Monitoring","desc":"Retainer-based continuous security monitoring and quarterly audit packages are available."}],"faqs":[{"q":"How much does a cybersecurity audit cost?","a":"Pricing depends on the scope and depth of the engagement. A focused vulnerability assessment for a web application typically starts at ₱30,000–₱80,000. A comprehensive penetration test with compliance review and full remediation support commonly ranges from ₱120,000 to ₱350,000+, depending on system complexity and regulatory requirements."},{"q":"How do you handle discovered vulnerabilities?","a":"We provide a detailed report with severity ratings (Critical/High/Medium/Low), reproduction steps, and clear recommended fixes — then work with your team through full remediation until risks are resolved."},{"q":"Do you offer ongoing security monitoring?","a":"Yes. We offer retainer-based continuous security monitoring, quarterly penetration test cycles, and dedicated incident response support for businesses that need ongoing protection."}]}'::jsonb, 11, true) on conflict (slug) do update set title = excluded.title, short_desc = excluded.short_desc, icon = excluded.icon, color = excluded.color, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('brainspark-app', 'BrainSpark', 'Flashcard & Quiz Learning App', 'Education', '{"Mobile","Enterprise"}'::text[], '{"Flutter","Supabase","Dart"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217678/1_nxiqfg.png', 'Adaptive flashcard and quiz learning app that helps students master any subject using spaced-repetition, mastery tracking, and timed quiz sessions — built with Flutter and Supabase.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773984938/10_ychopg.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217678/1_nxiqfg.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217670/2_kougck.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217671/3_rmwbm2.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217675/4_ywjq3v.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217676/5_w3cyzg.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217674/6_eldeog.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217674/7_xh4uqx.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217671/8_efs3ui.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773217678/9_obgoli.png"],"overview":"BrainSpark is a mobile learning app that helps users study smarter using spaced-repetition flashcards and timed quiz sessions. Users organize cards into decks by topic, track mastery progress, and review performance analytics.","problem":"Traditional study methods like re-reading notes are inefficient and hard to measure. Learners struggle to identify weak areas and end up wasting time on material they already know before exams.","solution":"BrainSpark combines active recall with performance tracking. Cards are flagged by difficulty, mastery is computed from accuracy scores, and study sessions surface weak cards more frequently.","features":["Spaced-Repetition Flashcards","Timed Quiz Sessions","Mastery Tracking by Deck","Deck Creation and Organization","Difficulty-Based Card Prioritization","Daily Study Goal and Streaks","Quiz Performance Analytics","Offline Study with Auto Sync","Cross-Device Progress Sync","Smart Review Reminders","Dark and Light Theme","Card Search and Filter"],"technologies":["Flutter","Dart","Supabase","PostgreSQL"],"results":[{"metric":"Quiz Completion Rate","value":"91%"},{"metric":"Avg Study Sessions/Day","value":"3.4"},{"metric":"Mastery Improvement","value":"+67%"},{"metric":"User Rating","value":"4.8/5"}],"testimonial":{"quote":"BrainSpark completely transformed how I study. The spaced repetition system kept me focused on what actually needed review.","author":"Andrea Cruz","role":"College Student, UP Diliman"}}'::jsonb, true, 0, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('circlo-app', 'Circlo', 'Community Social Networking App', 'Social Media', '{"Mobile","Enterprise"}'::text[], '{"React Native","TypeScript","Firebase","Firestore"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226881/2_b49kvp.png', 'Community-first social app for Filipino niche groups where users join circles, share posts, and engage through focused feeds designed for meaningful interaction.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226881/1_fdhgdn.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226901/2_b49kvp.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226902/3_ybp9rl.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226910/4_ljfuis.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226890/5_galahe.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226885/6_wiavkr.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226884/7_ucq5kk.png"],"overview":"Circlo is a mobile social platform where users join interest-based circles, publish media posts, and discover local communities across the Philippines.","problem":"Users in Cebu, Davao, and Metro Manila wanted focused community spaces without the noise of mainstream social feeds.","solution":"We built circle-based feeds, live interactions, and localized discovery to keep engagement relevant and community-centered.","features":["Interest-Based Circle Creation","Circle Join and Leave Controls","Media Post Publishing","Threaded Comments and Replies","Reaction Counters in Real Time","User Profiles with Activity History","Circle Discovery by Topic","Push Notifications for Mentions","In-App Notification Center","Follow and Follower System","Dark and Light Theme","Offline Feed Caching"],"technologies":["React Native","TypeScript","Firebase","Firestore"],"results":[{"metric":"Monthly Active Users","value":"28,000+"},{"metric":"Avg Session Duration","value":"14.8 min"},{"metric":"7-Day Retention","value":"62%"},{"metric":"App Store Rating","value":"4.7/5"}],"testimonial":{"quote":"Circlo helped us build active local communities without relying on noisy mainstream platforms.","author":"Mika De Leon","role":"Founder, Circlo Philippines"}}'::jsonb, true, 1, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('eventora-app', 'Eventora', 'Event Discovery and Ticketing App', 'Events and Entertainment', '{"Mobile","Enterprise"}'::text[], '{"Flutter","Dart","Appwrite","PostgreSQL"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226894/2_ufkg2o.png', 'End-to-end event app for discovery, bookings, and organizer operations, used by local organizers in Metro Manila, Clark, and Iloilo.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226894/1_rujvuz.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226907/2_ufkg2o.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226905/3_sz1odn.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226899/4_ymmoo0.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226910/5_eub5vh.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226895/6_m7n10j.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226897/7_mr4ho0.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226891/8_izjo3h.png"],"overview":"Eventora centralizes event creation, attendee management, ticket issuance, and live organizer updates in one mobile experience.","problem":"Local organizers relied on spreadsheets and messaging apps, causing overbooking and poor attendee communication.","solution":"We delivered mobile-first ticketing, QR validation, and live announcement tools for smooth event operations.","features":["Event Discovery by Category","Location-Based Event Search","Organizer Event Creation Panel","Tiered Ticket Booking Flow","QR Ticket Wallet","Real-Time Seat Availability","Event Bookmarking","Calendar Date Filtering","Organizer Guest List Management","QR Scan Check-In Mode","Event Announcement Push Alerts","Post-Event Rating Prompt"],"technologies":["Flutter","Dart","Appwrite","PostgreSQL"],"results":[{"metric":"Tickets Processed","value":"52,000+"},{"metric":"Check-In Time Reduction","value":"-71%"},{"metric":"No-Show Reduction","value":"-29%"},{"metric":"Organizer Satisfaction","value":"4.8/5"}],"testimonial":{"quote":"Eventora removed the chaos from our event days and made ticket management effortless.","author":"Jules Mercado","role":"Operations Lead, Manila Event Guild"}}'::jsonb, true, 2, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('fittrail-app', 'FitTrail', 'Workout and Fitness Tracking App', 'Health and Fitness', '{"Mobile","Enterprise"}'::text[], '{"Kotlin","Jetpack Compose","Room","Firebase"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982028/2_ylpfwk.png', 'Native Android workout tracker for gym users with progression analytics, smart session logging, and offline-first performance.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982028/1_zqaioy.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982029/2_ylpfwk.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982029/3_ofki2v.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982029/4_wmse2l.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982030/5_kgdtk6.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982030/6_nsvwab.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982029/7_s0dfd7.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982029/8_en5jwh.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982030/9_zm7nie.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982028/10_euuhjj.png"],"overview":"FitTrail helps users log workouts quickly, track strength progression, and stay consistent with intelligent session tools.","problem":"Serious gym users needed a distraction-free app focused on logging and progress instead of social feed features.","solution":"We built an offline-first Android app with structured workout logging, rest timers, and progression dashboards.","features":["Custom Exercise Library","Workout Session Builder","Set, Rep, and Weight Logging","In-Session Rest Timer","Workout History Timeline","Strength Progress Charts","Body Weight Tracking","Superset Grouping","Previous Session Snapshot","Cloud Backup and Restore","Health Data Sync","Offline Workout Mode"],"technologies":["Kotlin","Jetpack Compose","Room","Firebase"],"results":[{"metric":"Weekly Active Users","value":"11,400+"},{"metric":"Avg Workouts Logged/User","value":"4.1/week"},{"metric":"Data Loss Incidents","value":"0 reported"},{"metric":"Play Store Rating","value":"4.8/5"}],"testimonial":{"quote":"FitTrail is exactly what lifters need: fast logging, clear progress, no unnecessary clutter.","author":"Paolo Ramirez","role":"Head Coach, IronLab QC"}}'::jsonb, true, 3, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('habitforge-app', 'HabitForge', 'Habit Tracking and Routine App', 'Productivity', '{"Mobile","Enterprise"}'::text[], '{"Flutter","Dart","Supabase","PostgreSQL"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982046/2_oinafj.png', 'Habit and routine tracker built for long-term behavior change with streak analytics and smart reminder logic.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982046/1_ejwxk0.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982046/2_oinafj.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982046/3_nsxkva.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982046/4_bvykmy.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982050/5_auue3o.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982050/6_lbmu5f.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982050/7_yqnqq0.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982050/8_rpjp40.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982050/9_drqdn7.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982045/10_bsu8yc.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982045/11_glra74.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982045/12_yfz7ko.png"],"overview":"HabitForge helps users design routines, complete daily habits, and understand consistency patterns through visual analytics.","problem":"Users struggled to maintain routines because most trackers offered basic checkboxes without meaningful feedback.","solution":"We created a data-backed habit system with routines, streak protection, and trend visualizations to sustain momentum.","features":["Habit Creation with Custom Frequency","Routine Grouping by Time Block","One-Tap Daily Check-In","Current and Longest Streak Tracking","Yearly Habit Heatmap View","Weekly Completion Analytics","Milestone Celebrations","Streak Protection Alerts","Per-Habit Reminder Scheduling","Calendar Completion View","Drag-and-Drop Habit Reordering","Offline Check-In Queue"],"technologies":["Flutter","Dart","Supabase","PostgreSQL"],"results":[{"metric":"Avg 30-Day Retention","value":"69%"},{"metric":"Daily Check-Ins","value":"41,000+"},{"metric":"Avg Habit Completion","value":"78%"},{"metric":"User Rating","value":"4.7/5"}],"testimonial":{"quote":"HabitForge helped our users stay consistent because the progress feedback is very clear and motivating.","author":"Angela Co","role":"Product Owner, BetterDays PH"}}'::jsonb, true, 4, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('insightly-app', 'Insightly', 'Business Analytics Dashboard App', 'Business Intelligence', '{"Mobile","Enterprise"}'::text[], '{"Flutter","Dart","REST API","PostgreSQL"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982078/2_mgk4sc.png', 'Mobile KPI dashboard that consolidates business metrics into clear, decision-ready insights for teams and executives.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982078/1_vgzebd.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982081/2_mgk4sc.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982080/3_ph2nsf.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982079/4_eqj6hu.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982078/5_qrb87r.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982085/6_jyzfdb.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982083/7_irr2uk.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982085/8_frov6r.png"],"overview":"Insightly delivers KPI cards, trend reporting, and actionable insight summaries for fast daily business decision-making.","problem":"Executives had to switch between multiple BI tools and spreadsheets to get a complete performance picture.","solution":"We built one mobile analytics cockpit with goal tracking, report snapshots, and alert-style insight summaries.","features":["KPI Dashboard Cards","Weekly Revenue Trend View","Monthly Comparison Reports","Traffic Source Breakdown","Goal Progress Tracking","Status Labels by Goal","Insight Feed by Priority","Date Range Filtering","Executive Summary Snapshots","Alert Cards for Anomalies","Profile and Notification Settings","Cross-Platform Mobile and Desktop Build"],"technologies":["Flutter","Dart","REST API","PostgreSQL"],"results":[{"metric":"Decision Reporting Time","value":"-63%"},{"metric":"Daily Active Managers","value":"1,900+"},{"metric":"Goal Tracking Adoption","value":"84%"},{"metric":"Client Satisfaction","value":"4.8/5"}],"testimonial":{"quote":"Insightly gave our leadership one trusted dashboard and eliminated manual KPI reporting.","author":"Franco Velasco","role":"COO, Atlas Retail Group"}}'::jsonb, true, 5, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('moodleaf-app', 'MoodLeaf', 'Mood Tracking and Journaling App', 'Mental Wellness', '{"Mobile","Enterprise"}'::text[], '{"Flutter","Dart","Appwrite","PostgreSQL"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982091/2_pwlgqu.png', 'Private mood and journal app with trend detection and emotional analytics built for daily self-awareness habits.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982091/1_oywvp7.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982089/2_pwlgqu.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982090/3_j0radc.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982088/4_cqg0hk.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982090/5_wnkezo.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982088/6_krve6o.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982089/7_uaimtf.png"],"overview":"MoodLeaf helps users track emotions, log private notes, and identify recurring life factors that affect well-being.","problem":"Users and wellness coaches lacked structured mood history, making it difficult to detect emotional patterns over time.","solution":"We delivered a secure mood journal with analytics, tag correlations, reminders, and private-by-design data handling.","features":["Daily Mood Check-In","Mood Intensity Slider","Tagged Journal Entries","Monthly Mood Calendar","Mood History Search","Streak Tracking","Weekly and Monthly Trends","Tag Correlation Insights","Time-of-Day Mood Analysis","Encrypted Journal Content","Daily Reminder Notifications","Anonymous Trial Mode"],"technologies":["Flutter","Dart","Appwrite","PostgreSQL"],"results":[{"metric":"Daily Log Consistency","value":"74%"},{"metric":"Weekly Active Users","value":"9,600+"},{"metric":"30-Day Retention","value":"58%"},{"metric":"User Rating","value":"4.8/5"}],"testimonial":{"quote":"MoodLeaf made emotional tracking practical and safe for our counseling program participants.","author":"Dr. Nina Esteban","role":"Clinical Psychologist, MindCare PH"}}'::jsonb, true, 6, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('noteharbor-app', 'NoteHarbor', 'Rich Note-Taking and Organization App', 'Productivity', '{"Mobile","Enterprise"}'::text[], '{"Kotlin","Jetpack Compose","Room","Firebase"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982094/2_yjyrzz.png', 'Native Android notes app with rich text editing, tagging, and fast cloud sync for professionals and students.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982094/1_xfl1tr.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982095/2_yjyrzz.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982094/3_a2s7zn.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982095/4_cklxh8.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982095/5_cchz7x.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982096/6_dlqwrq.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982096/7_n7b1yb.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982099/8_ucagtx.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982100/9_art9ug.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982094/10_zbyc70.png"],"overview":"NoteHarbor combines rich text writing, deep organization tools, and offline-first speed in a modern Android experience.","problem":"Users needed a full-featured notes app without expensive subscription walls and slow web-based sync behavior.","solution":"We built a local-first notes platform with structured tags, folders, full-text search, and reliable cloud synchronization.","features":["Rich Text Note Editor","Pinned Notes","Folder and Tag Organization","Archive and Trash Workflow","30-Day Recovery Window","Word Count and Metadata","Full-Text Search","Smart Sort and Filters","Home Screen Shortcuts","Real-Time Multi-Device Sync","Offline Note Editing","Theme and Preference Settings"],"technologies":["Kotlin","Jetpack Compose","Room","Firebase"],"results":[{"metric":"Notes Created","value":"1.3M+"},{"metric":"Search Response Time","value":"<120 ms"},{"metric":"Sync Success Rate","value":"99.6%"},{"metric":"Play Store Rating","value":"4.8/5"}],"testimonial":{"quote":"NoteHarbor is fast, reliable, and organized exactly how power users want it.","author":"Rafael Ong","role":"Founder, StudyStack PH"}}'::jsonb, true, 7, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('pantrypilot-app', 'PantryPilot', 'Pantry and Grocery Management App', 'Household and Consumer', '{"Mobile","Enterprise"}'::text[], '{"React Native","TypeScript","Supabase","PostgreSQL"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982102/2_v0ngvs.png', 'Smart pantry inventory and grocery planning app that reduces household food waste with expiry and low-stock automation.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982102/1_grde5n.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982102/2_v0ngvs.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982103/3_xznrvb.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982103/4_ltpmfn.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982107/5_fdjk2o.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982105/6_nu9jtc.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982106/7_fgkdir.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982107/8_kpcfkf.png"],"overview":"PantryPilot lets households track inventory, detect expiring items, and auto-generate shopping lists based on real usage.","problem":"Families frequently overbought groceries and missed expiry dates due to manual, unstructured pantry tracking.","solution":"We created barcode-assisted inventory, shared household lists, and automated alerts for expiry and restocking.","features":["Pantry Inventory Dashboard","Barcode Product Scanning","Manual Item Entry","Auto Low-Stock Detection","Expiry Date Tracking","Shared Household Access","Smart Shopping List Builder","Shopping List Check-Off Flow","Household Member Roles","Category and Name Filtering","Offline List Caching","Expiry and Restock Alerts"],"technologies":["React Native","TypeScript","Supabase","PostgreSQL"],"results":[{"metric":"Food Waste Reduction","value":"-38%"},{"metric":"Monthly Active Households","value":"7,200+"},{"metric":"Missed Restocks","value":"-57%"},{"metric":"User Rating","value":"4.7/5"}],"testimonial":{"quote":"PantryPilot helped our users save money every month by preventing duplicate and expired purchases.","author":"Mariane Flores","role":"Product Manager, HomeFlow PH"}}'::jsonb, true, 8, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('pingnest-app', 'PingNest', 'Real-Time Group Messaging App', 'Communication', '{"Mobile","Enterprise"}'::text[], '{"React Native","TypeScript","Firebase","Realtime Database"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982113/2_kcz9pe.png', 'Fast chat app for Filipino teams and communities with channels, direct messages, and real-time presence tracking.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982113/1_svycls.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982115/2_kcz9pe.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982112/3_hbej67.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982111/4_zribxj.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982112/5_mneee6.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982115/6_ednqke.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982117/7_ucdzfc.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982117/8_hiajz5.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982118/9_q5u7pm.png"],"overview":"PingNest delivers low-latency chat, channel collaboration, and presence indicators for small teams and communities.","problem":"Small organizations needed a simple chat platform that was lighter than enterprise tools but more structured than SMS groups.","solution":"We launched a focused real-time messaging app with channels, DMs, reactions, and push notifications.","features":["Group Channel Creation","One-to-One Direct Messages","Real-Time Message Delivery","Media and File Attachments","Message Reactions","Read Receipt Indicators","Online Presence Status","Mention and Reply Support","Unread Notification Badges","Push Notifications","Message Search and Pagination","Offline Message Queue"],"technologies":["React Native","TypeScript","Firebase","Realtime Database"],"results":[{"metric":"Messages Sent/Month","value":"3.6M+"},{"metric":"Median Delivery Latency","value":"<400 ms"},{"metric":"Team Adoption","value":"420 groups"},{"metric":"User Rating","value":"4.7/5"}],"testimonial":{"quote":"PingNest gave our distributed teams a focused communication space without unnecessary complexity.","author":"Kenneth Chua","role":"Operations Director, BuildWorks PH"}}'::jsonb, true, 9, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('pocketpulse-app', 'PocketPulse', 'Personal Finance and Budgeting App', 'Fintech', '{"Mobile","Enterprise"}'::text[], '{"Kotlin","Jetpack Compose","Room","Firebase"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982120/2_liyxyi.png', 'Native Android budgeting app that tracks spending, account balances, and monthly financial health with offline-first reliability.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982120/1_j6uts5.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982124/2_liyxyi.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982126/3_dat6ee.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982124/4_y7arc6.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982125/5_ar07ci.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982127/6_pxedhd.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982128/7_uq5myw.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982120/8_dst2lq.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982121/9_lnwpdh.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982122/10_pmcviu.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982123/11_iyem0a.png"],"overview":"PocketPulse helps users manage budgets, monitor spending, and understand monthly cash flow without subscription paywalls.","problem":"Many Filipinos tracked budgets manually in spreadsheets, making daily money management inconvenient and inconsistent.","solution":"We built a local-first finance app with budget controls, multi-account tracking, and optional secure cloud backup.","features":["Income and Expense Logging","Custom Budget Categories","Monthly Budget Limits","Multiple Account Tracking","Net Worth Summary","Transaction Search and Filters","Category Spending Charts","Cash Flow Trend Reports","Budget Threshold Alerts","Recurring Summary Notifications","Optional Cloud Backup","Offline Financial Tracking"],"technologies":["Kotlin","Jetpack Compose","Room","Firebase"],"results":[{"metric":"Monthly Transactions Logged","value":"890,000+"},{"metric":"Budget Overruns Reduced","value":"-33%"},{"metric":"Monthly Active Users","value":"24,500+"},{"metric":"Play Store Rating","value":"4.8/5"}],"testimonial":{"quote":"PocketPulse made personal budgeting practical for users who never stuck to spreadsheet tracking.","author":"Erika Mendoza","role":"Head of Product, PesoWise PH"}}'::jsonb, true, 10, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('savora-app', 'Savora', 'Recipe and Meal Planning App', 'Food and Lifestyle', '{"Mobile","Enterprise"}'::text[], '{"Flutter","Dart","Appwrite","PostgreSQL"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982131/2_j5wfva.png', 'Recipe discovery and weekly meal planner app that turns saved dishes into structured shopping-ready meal plans.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982131/1_zkhggh.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982134/2_j5wfva.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982138/3_fzkycu.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982135/4_f5csmq.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982131/5_fxzxod.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982136/6_wcjihb.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982135/7_iicflf.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982134/8_bv0gsb.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982139/9_ysoarf.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982137/10_wrwn0a.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982131/11_tqeox2.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982130/12_jh2bcm.png"],"overview":"Savora helps users find recipes, build weekly meal plans, and auto-generate shopping lists from planned meals.","problem":"Home cooks managed recipes, meal planning, and grocery lists across separate tools, creating weekly friction.","solution":"We combined discovery, planning, and shopping in one app flow tailored to everyday cooking routines.","features":["Recipe Feed by Cuisine","Advanced Recipe Search","Recipe Save to Collections","Weekly Meal Calendar","Drag-and-Drop Meal Planning","Serving Size Adjuster","Auto Shopping List Generation","Ingredient Quantity Merge","Shopping List Category Grouping","Recipe Ratings and Reviews","Sunday Planning Reminder","Offline Recipe Cache"],"technologies":["Flutter","Dart","Appwrite","PostgreSQL"],"results":[{"metric":"Weekly Meal Plans Created","value":"18,000+"},{"metric":"Shopping Prep Time Saved","value":"-46%"},{"metric":"Recipe Save Rate","value":"72%"},{"metric":"User Rating","value":"4.8/5"}],"testimonial":{"quote":"Savora gave our users a complete meal workflow from recipe discovery to grocery checkout.","author":"Chef Lianne Cruz","role":"Content Director, Kusina Daily"}}'::jsonb, true, 11, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('skypeek-app', 'SkyPeek', 'Weather Forecast and Alert App', 'Weather and Utilities', '{"Mobile","Enterprise"}'::text[], '{"React Native","TypeScript","Expo","REST API"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982141/2_pwlmyz.png', 'Modern weather app with hourly forecasts, radar maps, and severe weather alerts for major Philippine cities and provinces.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982141/1_ktwyty.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982147/2_pwlmyz.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982147/3_cvdvkx.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982142/4_owtdxh.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982145/5_yy4rja.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982143/6_gxmdrd.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982144/7_jojjiq.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982148/8_wfrmfb.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982146/9_ozpzj8.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982140/10_vfrghj.png"],"overview":"SkyPeek provides detailed weather conditions, forecast breakdowns, and proactive alerts for changing weather risks.","problem":"Users needed a clear, ad-light weather app with detailed local forecasts and meaningful severe condition alerts.","solution":"We built a weather app that combines polished UI, robust forecast data, and location-based alert logic.","features":["Current Weather Conditions","48-Hour Forecast Timeline","7-Day Forecast Cards","UV Index Risk Guidance","Air Quality Monitoring","Rain and Wind Indicators","Saved Location Management","Location Search and Geocoding","Interactive Radar Map","Severe Weather Alerts","Temperature Unit Toggle","Offline Forecast Cache"],"technologies":["React Native","TypeScript","Expo","REST API"],"results":[{"metric":"Daily Forecast Checks","value":"110,000+"},{"metric":"Alert Open Rate","value":"68%"},{"metric":"Saved Locations/User","value":"3.1 avg"},{"metric":"App Rating","value":"4.7/5"}],"testimonial":{"quote":"SkyPeek became our users preferred weather app because it is fast, accurate, and easy to read.","author":"Harvey Tan","role":"Founder, KlimaTech PH"}}'::jsonb, true, 12, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('tasknest-app', 'TaskNest', 'Task and Workspace Management App', 'Productivity and Collaboration', '{"Mobile","Enterprise"}'::text[], '{"Kotlin","Jetpack Compose","Supabase","PostgreSQL"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982150/2_ntebxo.png', 'Task manager combining personal planning and lightweight team workspaces with recurring schedules and reliable reminders.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982150/1_sbzss1.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982152/2_ntebxo.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982153/3_fyenk6.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982154/4_bu2p7n.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982155/5_xdc0gx.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982156/6_fsupk0.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982156/7_qsmkfk.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982157/8_wgpubd.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982158/9_gaba9z.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982150/10_jpfj2s.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982152/11_utcit3.png"],"overview":"TaskNest unifies personal to-dos and shared team tasks in a mobile-first system optimized for consistency and execution.","problem":"Users switched between simple to-do apps and heavy PM tools, creating fragmented workflows and missed deadlines.","solution":"We designed a hybrid productivity platform with personal lists, team workspaces, and dependable reminder automation.","features":["Task Creation with Priorities","Subtask Checklists","Recurring Task Rules","Today and Upcoming Views","Bulk Task Actions","Quick Capture Inbox","Workspace Board View","Task Assignment by Member","Task Comment Threads","Invite Link Collaboration","Exact Reminder Scheduling","Offline Personal Task Mode"],"technologies":["Kotlin","Jetpack Compose","Supabase","PostgreSQL"],"results":[{"metric":"Tasks Completed/Month","value":"1.1M+"},{"metric":"Missed Deadlines","value":"-41%"},{"metric":"Active Workspaces","value":"3,800+"},{"metric":"User Rating","value":"4.8/5"}],"testimonial":{"quote":"TaskNest gave us the right balance of personal productivity and team visibility in one app.","author":"Lara Dimaano","role":"Operations Manager, Vertex Creatives PH"}}'::jsonb, false, 13, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('tradeloop-app', 'TradeLoop', 'Peer-to-Peer Marketplace App', 'E-Commerce Marketplace', '{"Mobile","Enterprise"}'::text[], '{"Flutter","Dart","Supabase","PostgreSQL"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982159/2_bimfaa.png', 'Local marketplace app for buying, selling, and trading second-hand items with structured offers and in-app deal chat.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982159/1_gjjqjl.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982162/2_bimfaa.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982162/3_lpixib.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982164/4_kvvqyc.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982163/5_bau44o.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982166/6_vt2dso.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982165/7_fnz9zl.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982167/8_sewqve.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982167/9_mbvgqw.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982161/10_yrmzvx.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773982160/11_qw0lro.png"],"overview":"TradeLoop powers trusted local commerce with listing workflows, offer negotiation, and transaction reputation scoring.","problem":"Existing classified apps had poor mobile UX and low trust, making local buy-and-sell transactions difficult to close.","solution":"We built a marketplace centered on verified profiles, structured offer states, and real-time buyer-seller communication.","features":["Listing Creation with Photos","Cash or Trade Preference Options","Category and Distance Filters","Watchlist and Price Drop Alerts","Structured Offer Submission","Counter-Offer Workflow","Real-Time Deal Chat","Listing Expiry and Relist Prompts","Buyer and Seller Ratings","Trust Badge Indicators","Listing Report and Moderation","Map-Based Listing Discovery"],"technologies":["Flutter","Dart","Supabase","PostgreSQL"],"results":[{"metric":"Listings Published","value":"95,000+"},{"metric":"Deal Completion Rate","value":"64%"},{"metric":"Avg Time to First Offer","value":"3.2 hrs"},{"metric":"User Rating","value":"4.7/5"}],"testimonial":{"quote":"TradeLoop made local buy-and-sell safer and more structured for both new and experienced sellers.","author":"Jerome Villanueva","role":"Co-Founder, TradeLoop PH"}}'::jsonb, false, 14, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('appoint2day-web', 'Appoint2Day', 'Online Tutor Booking and Appointment System', 'Education', '{"Web","Enterprise"}'::text[], '{"Python","HTML","CSS","JavaScript"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851678/1_wlnvxl.png', 'Online Tutor Booking and Appointment System deployed for Philippine clients with production-grade workflows, compliance-ready records, and measurable operational impact.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851678/1_wlnvxl.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851678/2_uvlj1v.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851679/3_phaypr.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851679/4_qclzrf.png"],"overview":"Appoint2Day is a online tutor booking and appointment system built for Philippine organizations to streamline operations and improve service delivery.","problem":"The client relied on manual processes and disconnected tools, resulting in delays, data errors, and limited visibility for management decisions.","solution":"We delivered an end-to-end platform with role-based access, process automation, audit-ready records, and real-time dashboards tailored to the client workflow.","features":["Role-Based Access Control","Dashboard and KPI Overview","Advanced Search and Filters","Approval and Validation Workflow","Automated Notifications","Audit Trail and Activity Logs","Exportable Reports (PDF/CSV)","Multi-Tenant or Branch Support","Configurable User Permissions","Data Import and Bulk Upload","Document and Attachment Management","Calendar and Scheduling Module","Public-Facing Request or Booking Form","Analytics and Trend Insights","System Settings and Customization","Mobile-Responsive Interface"],"technologies":["Python","Flask","HTML","CSS","JavaScript","MySQL","Bootstrap","SMTP"],"results":[{"metric":"Process Time Reduction","value":"-58%"},{"metric":"Data Accuracy","value":"99.2%"},{"metric":"User Adoption","value":"93%"},{"metric":"Client Satisfaction","value":"4.8/5"}],"testimonial":{"quote":"Appoint2Day improved our daily operations and gave us complete visibility of critical workflows.","author":"Project Owner","role":"Client Representative, Philippines"}}'::jsonb, false, 15, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('brgy-alacan-funding-system', 'Brgy Alacan Funding System', 'Barangay Financial Management System', 'Government', '{"Software","Enterprise"}'::text[], '{"Java","MySQL","JFrame","Desktop"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851603/1_fp2mpj.png', 'Barangay Financial Management System deployed for Philippine clients with production-grade workflows, compliance-ready records, and measurable operational impact.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851603/1_fp2mpj.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851603/2_s3goxi.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851604/3_lo0ihq.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1772851604/4_pmpm6v.png"],"overview":"Brgy Alacan Funding System is a barangay financial management system built for Philippine organizations to streamline operations and improve service delivery.","problem":"The client relied on manual processes and disconnected tools, resulting in delays, data errors, and limited visibility for management decisions.","solution":"We delivered an end-to-end platform with role-based access, process automation, audit-ready records, and real-time dashboards tailored to the client workflow.","features":["Role-Based Access Control","Dashboard and KPI Overview","Advanced Search and Filters","Approval and Validation Workflow","Automated Notifications","Audit Trail and Activity Logs","Exportable Reports (PDF/CSV)","Mobile-Responsive Interface","Offline Draft and Sync Support","In-App Activity Timeline","Push Notifications","Secure Authentication"],"technologies":["Java","Swing (JFrame)","MySQL","JasperReports","iText PDF","SMTP"],"results":[{"metric":"Process Time Reduction","value":"-58%"},{"metric":"Data Accuracy","value":"99.2%"},{"metric":"User Adoption","value":"93%"},{"metric":"Client Satisfaction","value":"4.8/5"}],"testimonial":{"quote":"Brgy Alacan Funding System improved our daily operations and gave us complete visibility of critical workflows.","author":"Project Owner","role":"Client Representative, Philippines"}}'::jsonb, false, 16, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
