insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('aniki-figures', 'Aniki Figures', 'Premium Anime Figure E-Commerce Platform', 'Retail and Collectibles', '{"E-commerce","Web"}'::text[], '{"Next.js","Express","MongoDB","TypeScript"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219902/1_njmh8v.png', 'Full-stack anime figure and collectibles e-commerce platform with advanced catalog search, pre-orders, and modern storefront UX.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219902/1_njmh8v.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219898/2_wetshz.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219893/3_vxp54n.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219893/4_yh5vvf.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219899/5_sdr8fe.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219894/6_yjj5y8.png"],"overview":"Aniki Figures is a modern collectibles marketplace focused on anime figures, Funko Pop, and model kits. The platform combines rich catalog browsing, wishlist workflows, and secure account-based ordering.","problem":"Collectors needed a specialized storefront with better product discovery, franchise-based filtering, and pre-order support that general marketplaces did not provide effectively.","solution":"We built a focused e-commerce system with advanced multi-criteria search, persistent cart state, wishlist features, and pre-order handling tailored for collectibles buyers.","features":["Role-Based Access Control","Dashboard and KPI Overview","Advanced Search and Filters","Approval and Validation Workflow","Automated Notifications","Audit Trail and Activity Logs","Exportable Reports (PDF/CSV)","Multi-Tenant or Branch Support","Configurable User Permissions","Data Import and Bulk Upload","Document and Attachment Management","Calendar and Scheduling Module","Public-Facing Request or Booking Form","Analytics and Trend Insights","System Settings and Customization","Mobile-Responsive Interface"],"technologies":["Next.js","TypeScript","Express.js","MongoDB","Mongoose","Tailwind CSS","Zustand","JWT"],"results":[{"metric":"Catalog Conversion Lift","value":"+34%"},{"metric":"Avg Session Duration","value":"11.2 min"},{"metric":"Pre-Order Completion Rate","value":"88%"},{"metric":"Client Satisfaction","value":"4.8/5"}],"testimonial":{"quote":"Aniki Figures gave us the exact collectible-commerce flow our community needed, from discovery to pre-order checkout.","author":"Project Owner","role":"Client Representative, Philippines"}}'::jsonb, false, 42, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('auto-ticketing-system', 'Auto Ticketing System', 'Parking Ticketing and Collections Management System', 'Transport and Public Services', '{"Web","Enterprise"}'::text[], '{"Laravel","React","Capacitor","TypeScript"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219909/1_hmeshh.png', 'Mobile-first parking ticketing and payment platform with thermal printing, collections analytics, and multi-role operations.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219909/1_hmeshh.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219908/2_sou54w.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219913/3_zqlxjn.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219912/4_ln7ic6.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219919/5_kkcfnm.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219919/6_v63hwp.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219916/7_vyvwqx.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219920/8_b8evrr.png"],"overview":"Auto Ticketing System digitizes parking operations from ticket issuance through payment and remittance reporting. It supports on-ground enforcers, finance monitoring, and printer-integrated receipt workflows.","problem":"Manual and fragmented parking collection workflows caused inconsistent records, delayed remittance consolidation, and weak operational visibility for administrators.","solution":"We delivered a PWA-driven ticketing and payment system with role-based dashboards, PT-210 Bluetooth printing support, and real-time collections analytics.","features":["Role-Based Access Control","Dashboard and KPI Overview","Advanced Search and Filters","Approval and Validation Workflow","Automated Notifications","Audit Trail and Activity Logs","Exportable Reports (PDF/CSV)","Multi-Tenant or Branch Support","Configurable User Permissions","Data Import and Bulk Upload","Document and Attachment Management","Calendar and Scheduling Module","Public-Facing Request or Booking Form","Analytics and Trend Insights","System Settings and Customization","Mobile-Responsive Interface"],"technologies":["Laravel","React","TypeScript","Inertia.js","MySQL","Capacitor","Bluetooth LE","Tailwind CSS"],"results":[{"metric":"Ticket Processing Time","value":"-52%"},{"metric":"Collection Reconciliation Accuracy","value":"99.1%"},{"metric":"Daily Ticket Throughput","value":"+41%"},{"metric":"Client Satisfaction","value":"4.8/5"}],"testimonial":{"quote":"The system streamlined daily parking operations and made remittance tracking far more reliable for our teams.","author":"Project Owner","role":"Client Representative, Philippines"}}'::jsonb, false, 43, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('bez-tower-and-residences', 'Bez Tower and Residences', 'Hotel Management and Reservation System', 'Hospitality', '{"Web","Enterprise"}'::text[], '{"Laravel","MySQL","Blade","Chart.js"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219932/1_hob3ua.png', 'End-to-end hotel operations platform covering room management, reservations, payment verification, housekeeping, and reports.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219932/1_hob3ua.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219928/2_sx5uxj.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219938/3_mmvpmh.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219947/Screenshot_2026-03-08_141604_ct4gqz.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219936/4_pgxptz.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219931/5_bb6hy9.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219937/6_hyo8n9.png"],"overview":"Bez Tower and Residences centralizes hotel operations in a single platform, including reservations, guest records, payment verification, and housekeeping workflows.","problem":"Hotel staff relied on disconnected records and manual coordination, causing reservation conflicts, delayed payment checks, and reduced service efficiency.","solution":"We implemented a role-based management suite with occupancy analytics, booking lifecycle tracking, and integrated operational dashboards for all hotel functions.","features":["Role-Based Access Control","Dashboard and KPI Overview","Advanced Search and Filters","Approval and Validation Workflow","Automated Notifications","Audit Trail and Activity Logs","Exportable Reports (PDF/CSV)","Multi-Tenant or Branch Support","Configurable User Permissions","Data Import and Bulk Upload","Document and Attachment Management","Calendar and Scheduling Module","Public-Facing Request or Booking Form","Analytics and Trend Insights","System Settings and Customization","Mobile-Responsive Interface"],"technologies":["Laravel","PHP","MySQL","Blade","Chart.js","Tailwind CSS","Laravel Breeze","Mail"],"results":[{"metric":"Booking Processing Time","value":"-47%"},{"metric":"Occupancy Reporting Accuracy","value":"98.9%"},{"metric":"Housekeeping Turnaround Visibility","value":"+63%"},{"metric":"Client Satisfaction","value":"4.8/5"}],"testimonial":{"quote":"This platform gave us better control over reservations and daily hotel operations with clear real-time reporting.","author":"Project Owner","role":"Client Representative, Philippines"}}'::jsonb, false, 44, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('e-sabong', 'E-Sabong', 'Cockfighting Betting Management System', 'Gaming and Betting Operations', '{"Web","Enterprise"}'::text[], '{"Laravel","React","Inertia.js","TypeScript"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220351/1_whnb9u.png', 'Web-based betting management platform for e-sabong events with live fight workflows, teller operations, and financial tracking.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220351/1_whnb9u.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220360/2_lzdgpj.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220356/3_k5hxk9.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220350/4_l1amtb.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220354/5_blmzyp.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220357/6_iliuwz.png"],"overview":"E-Sabong manages end-to-end betting operations from fight setup and live wager intake to result declaration, payout validation, and reporting.","problem":"Manual and fragmented fight betting workflows increased risk of disputes, delayed payouts, and limited visibility over teller-level transactions.","solution":"We built a centralized, role-based betting operations system with real-time updates, ticket controls, payout validation, and consolidated analytics dashboards.","features":["Role-Based Access Control","Dashboard and KPI Overview","Advanced Search and Filters","Approval and Validation Workflow","Automated Notifications","Audit Trail and Activity Logs","Exportable Reports (PDF/CSV)","Multi-Tenant or Branch Support","Configurable User Permissions","Data Import and Bulk Upload","Document and Attachment Management","Calendar and Scheduling Module","Public-Facing Request or Booking Form","Analytics and Trend Insights","System Settings and Customization","Mobile-Responsive Interface"],"technologies":["Laravel","React","TypeScript","Inertia.js","MySQL","Tailwind CSS","Vite","PWA"],"results":[{"metric":"Bet Reconciliation Time","value":"-49%"},{"metric":"Payout Processing Accuracy","value":"99.3%"},{"metric":"Fight Operations Throughput","value":"+38%"},{"metric":"Client Satisfaction","value":"4.7/5"}],"testimonial":{"quote":"The platform modernized our betting operations and significantly improved transaction control and speed.","author":"Project Owner","role":"Client Representative, Philippines"}}'::jsonb, false, 45, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('rmdc-dental-clinic', 'RMDC', 'Dental Clinic Management System', 'Healthcare', '{"Enterprise","Web"}'::text[], '{"Laravel","MySQL","Tailwind CSS","Firebase"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220346/1_mqpgr3.png', 'Comprehensive dental clinic platform for appointments, patient records, inventory, payment workflows, and real-time notifications.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220346/1_mqpgr3.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219968/2_lxjthm.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220344/3_ialflv.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773219968/4_o7jp7p.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220348/5_xma28t.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220343/6_ngyrb8.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773220343/7_swsxm6.png"],"overview":"RMDC is a clinic operations platform designed to handle patient journeys from online booking to treatment tracking, payment processing, and follow-up communication.","problem":"Clinic teams needed a reliable digital workflow to reduce appointment conflicts, improve records access, and monitor daily operations across branches.","solution":"We implemented a full-featured management system with appointment control, patient records, inventory and payment integration, and notification automation.","features":["Role-Based Access Control","Dashboard and KPI Overview","Advanced Search and Filters","Approval and Validation Workflow","Automated Notifications","Audit Trail and Activity Logs","Exportable Reports (PDF/CSV)","Multi-Tenant or Branch Support","Configurable User Permissions","Data Import and Bulk Upload","Document and Attachment Management","Calendar and Scheduling Module","Public-Facing Request or Booking Form","Analytics and Trend Insights","System Settings and Customization","Mobile-Responsive Interface"],"technologies":["Laravel","PHP","MySQL","Tailwind CSS","Vite","Firebase Cloud Messaging","PayMongo API","Leaflet.js"],"results":[{"metric":"Appointment Processing Time","value":"-44%"},{"metric":"Patient Data Retrieval Speed","value":"+57%"},{"metric":"Payment Confirmation Turnaround","value":"-39%"},{"metric":"Client Satisfaction","value":"4.8/5"}],"testimonial":{"quote":"RMDC helped us manage appointments and patient workflows much more efficiently across our clinic operations.","author":"Project Owner","role":"Client Representative, Philippines"}}'::jsonb, false, 46, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('smart-campus-assistant-and-navigator', 'Smart Campus Assistant and Navigator', 'Interactive Campus Directory and Navigation System', 'Education', '{"Academic","Web"}'::text[], '{"Laravel","Tailwind CSS","Alpine.js","MySQL"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773227129/1_kxhn0t.png', 'Campus navigation and information system with interactive floor maps, room search, events, announcements, and feedback ticketing.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773227129/1_kxhn0t.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773227136/2_t33mu5.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773227126/3_xujxup.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773227133/4_vnrq1m.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773227140/5_wnbypx.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773227127/6_q8vbpl.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773227124/7_hxj4t8.png"],"overview":"Smart Campus Assistant and Navigator helps students, faculty, and visitors navigate campus facilities while staying updated on events, reminders, and announcements.","problem":"Users found it difficult to locate rooms and access timely campus information, while administrators lacked a centralized channel for managing notices and feedback.","solution":"We developed an interactive campus platform with floor maps, room search, event and announcement modules, and a ticketing-based feedback workflow.","features":["Role-Based Access Control","Dashboard and KPI Overview","Advanced Search and Filters","Approval and Validation Workflow","Automated Notifications","Audit Trail and Activity Logs","Exportable Reports (PDF/CSV)","Multi-Tenant or Branch Support","Configurable User Permissions","Data Import and Bulk Upload","Document and Att