insert into projects(slug, title, system_type, industry, categories, tags, image, short_desc, details, is_featured, feature_order, is_published) values ('streamrock-realty', 'Streamrock Realty', 'Real Estate Listings and Management Platform', 'Real Estate', '{"E-commerce","Web"}'::text[], '{"MongoDB","Express","React","Node.js"}'::text[], 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226961/1_yrwjhf.png', 'Modern MERN real estate platform for property discovery, listing management, and direct inquiry workflows.', '{"images":["https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226961/1_yrwjhf.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226961/2_mgajbw.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226951/3_pr5eu6.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226951/4_xgodr6.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226957/5_ehv1xm.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226958/6_ir6jhd.png","https://res.cloudinary.com/dlu2bqrda/image/upload/v1773226956/7_qgq1o2.png"],"overview":"Streamrock Realty is a full-stack real estate platform for showcasing listings, filtering property options, and capturing buyer inquiries efficiently.","problem":"The client needed a modern digital property catalog to replace fragmented listing channels and improve lead conversion quality.","solution":"We built a responsive MERN platform with categorized listings, advanced filters, and inquiry workflows connected to centralized lead records.","features":["Role-Based Access Control","Dashboard and KPI Overview","Advanced Search and Filters","Approval and Validation Workflow","Automated Notifications","Audit Trail and Activity Logs","Exportable Reports (PDF/CSV)","Multi-Tenant or Branch Support","Configurable User Permissions","Data Import and Bulk Upload","Document and Attachment Management","Calendar and Scheduling Module","Public-Facing Request or Booking Form","Analytics and Trend Insights","System Settings and Customization","Mobile-Responsive Interface"],"technologies":["React","Node.js","Express.js","MongoDB","Vite","Tailwind CSS","Mongoose","REST API"],"results":[{"metric":"Qualified Inquiry Rate","value":"+36%"},{"metric":"Listing Discovery Speed","value":"+43%"},{"metric":"Mobile Engagement","value":"+48%"},{"metric":"Client Satisfaction","value":"4.8/5"}],"testimonial":{"quote":"Streamrock Realty gave us a professional listing platform that improved discoverability and lead quality across our portfolio.","author":"Project Owner","role":"Client Representative, Philippines"}}'::jsonb, false, 48, true) on conflict (slug) do update set title = excluded.title, system_type = excluded.system_type, industry = excluded.industry, categories = excluded.categories, tags = excluded.tags, image = excluded.image, short_desc = excluded.short_desc, details = excluded.details, is_featured = excluded.is_featured, feature_order = excluded.feature_order, is_published = excluded.is_published, updated_at = now();
