insert into team_members(name, role, bio, avatar, linkedin, github, portfolio, sort_order, is_active) values ('Jedidia Shekainah Garcia', 'Founder & CEO', 'Co-founded PROGREX in 2025 with a drive to build software that actually works for the people using it. Handles product direction, client relationships, and keeps the team aligned on what matters. Believes good software starts with understanding the problem, not rushing to the code.', 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1772372755/2e322f09-b81b-4794-a43c-8b35eff1003b_qqozqs.jpg', '#', '#', '#', 0, true);
insert into team_members(name, role, bio, avatar, linkedin, github, portfolio, sort_order, is_active) values ('Lee Rafael Torres', 'Co-Founder & CTO', 'Co-founded PROGREX and leads all technical decisions — from architecture to deployment. Obsessed with writing clean, maintainable code and building systems that hold up under real-world pressure. The kind of engineer who actually reads the docs.', 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1772373187/Lee-formatpic_sprpmg.png', '#', '#', '#', 1, true);
insert into team_members(name, role, bio, avatar, linkedin, github, portfolio, sort_order, is_active) values ('Bheberlyn O. Eugenio', 'Project Manager', 'Responsible for driving projects from concept to completion, ensuring timelines, budgets, and goals stay on track. Works closely with the team to align priorities and keep communication clear and actionable. Committed to delivering strategic, high-impact outcomes that create real value for clients.', 'https://res.cloudinary.com/dlu2bqrda/image/upload/v1772377390/berlyn_ykjlnw.png', '#', '#', '#', 2, true);
insert into ready_made_systems(slug, name, category, industry, tagline, short_desc, image, has_demo, details, sort_order, is_published) values ('proschool', 'ProSchool — School Management System', 'Education', 'School Management', 'The complete school management solution for modern institutions.', 'Manage students, teachers, attendance, grades, fees, and more from one powerful platform.', 'https://images.unsplash.com/photo-1580582932707-520aed937b7b?w=900&q=80', true, '{"features":["Student Enrollment & Profiles","Attendance Tracking","Grade & Report Cards","Fee Collection & Invoicing","Teacher Management","Parent Portal","Announcement Module","Library Management"],"faqs":[{"q":"Is the system customizable?","a":"Yes, we can customize branding, modules, and workflows."},{"q":"Do you provide training?","a":"Yes. Every purchase includes 1 day of free training."}],"pricing":[{"plan":"Starter","price":"₱8,000","type":"one-time","students":"Up to 200","support":"3 months"},{"plan":"Professional","price":"₱18,000","type":"one-time","students":"Up to 1,000","support":"6 months"},{"plan":"Enterprise","price":"₱35,000","type":"one-time","students":"Unlimited","support":"12 months"}],"screenshots":["/images/systems/proschool-1.jpg","/images/systems/proschool-2.jpg","/images/systems/proschool-3.jpg"]}'::jsonb, 0, true) on conflict (slug) do update set name = excluded.name, category = excluded.category, industry = excluded.industry, tagline = excluded.tagline, short_desc = excluded.short_desc, image = excluded.image, has_demo = excluded.has_demo, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into ready_made_systems(slug, name, category, industry, tagline, short_desc, image, has_demo, details, sort_order, is_published) values ('proinventory', 'ProInventory — Inventory Management System', 'Inventory', 'Retail / Warehouse', 'Real-time inventory control for businesses of all sizes.', 'Track stock, manage suppliers, automate re-orders, and generate detailed reports with ease.', 'https://images.unsplash.com/photo-1553413077-190dd305871c?w=900&q=80', true, '{"features":["Real-Time Stock Tracking","Barcode / QR Scanning","Supplier Management","Purchase Orders","Sales & Invoicing","Low Stock Alerts","Multi-Location Support","Advanced Reports"],"faqs":[{"q":"Does it work offline?","a":"Yes. The system works locally. Cloud sync is available as an add-on."},{"q":"Can I import existing data?","a":"Yes. We support Excel/CSV import for all data types."}],"pricing":[{"plan":"Basic","price":"₱5,000","type":"one-time","users":"2 Users","support":"3 months"},{"plan":"Business","price":"₱12,000","type":"one-time","users":"10 Users","support":"6 months"},{"plan":"Enterprise","price":"₱25,000","type":"one-time","users":"Unlimited","support":"12 months"}],"screenshots":["/images/systems/proinventory-1.jpg","/images/systems/proinventory-2.jpg"]}'::jsonb, 1, true) on conflict (slug) do update set name = excluded.name, category = excluded.category, industry = excluded.industry, tagline = excluded.tagline, short_desc = excluded.short_desc, image = excluded.image, has_demo = excluded.has_demo, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
insert into ready_made_systems(slug, name, category, industry, tagline, short_desc, image, has_demo, details, sort_order, is_published) values ('prohris', 'ProHRIS — HR & Payroll System', 'HR & Payroll', 'Human Resources', 'Automate HR operations and payroll with confidence.', 'Complete HR platform with payroll computation, DTR tracking, leave management, and compliance.', 'https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=900&q=80', true, '{"features":["Employee Database","Daily Time Record (DTR)","Payroll Computation","SSS / PhilHealth / Pag-IBIG","Withholding Tax","Leave Management","13th Month Pay","Payslip Generation"],"faqs":[{"q":"Is it BIR compliant?","a":"Yes. Tax computations follow the latest BIR and TRAIN Law rates."},{"q":"Can I integrate with biometric devices?","a":"Yes. We support most biometric timekeeping hardware."}],"pricing":[{"plan":"SME","price":"₱10,000","type":"one-time","employees":"Up to 30","support":"3 months"},{"plan":"Business","price":"₱20,000","type":"one-time","employees":"Up to 100","support":"6 months"},{"plan":"Corporate","price":"₱40,000","type":"one-time","employees":"Unlimited","support":"12 months"}],"screenshots":["/images/systems/prohris-1.jpg","/images/systems/prohris-2.jpg"]}'::jsonb, 2, true) on conflict (slug) do update set name = excluded.name, category = excluded.category, industry = excluded.industry, tagline = excluded.tagline, short_desc = excluded.short_desc, image = excluded.image, has_demo = excluded.has_demo, details = excluded.details, sort_order = excluded.sort_order, is_published = excluded.is_published, updated_at = now();
